def histogram(test):
    if not test:
        return {}
    letters = test.split()
    freq = {}
    for letter in letters:
        freq[letter] = freq.get(letter, 0) + 1
    max_count = max(freq.values())
    result = {k: v for k, v in freq.items() if v == max_count}
    return result

